pragma solidity ^0.8.0;

contract Calculator {
    uint256 public result;
    uint256 public lastOperation;

    event Operation(string op, uint256 a, uint256 b, uint256 result);

    function add(uint256 a, uint256 b) public returns (uint256) {
        result = a + b;
        lastOperation = result;
        emit Operation("add", a, b, result);
        return result;
    }

    function subtract(uint256 a, uint256 b) public returns (uint256) {
        require(a >= b, "Calculator: subtraction underflow");
        result = a - b;
        lastOperation = result;
        emit Operation("subtract", a, b, result);
        return result;
    }

    function multiply(uint256 a, uint256 b) public returns (uint256) {
        result = a * b;
        lastOperation = result;
        emit Operation("multiply", a, b, result);
        return result;
    }

    function divide(uint256 a, uint256 b) public returns (uint256) {
        require(b != 0, "Calculator: division by zero");
        result = a / b;
        lastOperation = result;
        emit Operation("divide", a, b, result);
        return result;
    }

    function reset() public {
        result = 0;
        lastOperation = 0;
    }
}

import type { KeystoreConsoleLog, KeystoreLoader } from "../types.js";
import type { HardhatRuntimeEnvironment } from "hardhat/types/hre";
import type { NewTaskActionFunction } from "hardhat/types/tasks";

import { UserDisplayMessages } from "../ui/user-display-messages.js";
import { setupKeystoreLoaderFrom } from "../utils/setup-keystore-loader-from.js";

interface TaskListArguments {
  dev: boolean;
}

const taskList: NewTaskActionFunction<TaskListArguments> = async (
  args,
  hre: HardhatRuntimeEnvironment,
): Promise<void> => {
  const keystoreLoader = setupKeystoreLoaderFrom(hre, args.dev);

  await list(args, keystoreLoader);
};

export const list = async (
  { dev }: TaskListArguments,
  keystoreLoader: KeystoreLoader,
  consoleLog: KeystoreConsoleLog = console.log,
): Promise<void> => {
  if (!(await keystoreLoader.isKeystoreInitialized())) {
    consoleLog(UserDisplayMessages.displayNoKeystoreSetErrorMessage(dev));
    process.exitCode = 1;
    return;
  }

  const keystore = await keystoreLoader.loadKeystore();

  const keys = await keystore.listUnverifiedKeys();

  if (keys.length === 0) {
    consoleLog(UserDisplayMessages.displayNoKeysInfoMessage(dev));
    return;
  }

  consoleLog(UserDisplayMessages.displayKeyListInfoMessage(keys, dev));
};

export default taskList;

import type { HardhatRuntimeEnvironmentHooks } from "../../../../types/hooks.js";
import type { GasAnalyticsManagerImplementation as GasAnalyticsManagerImplementationT } from "../gas-analytics-manager.js";

import { setGasAnalyticsManager } from "../helpers/accessors.js";

let GasAnalyticsManagerImplementation:
  | typeof GasAnalyticsManagerImplementationT
  | undefined;

export default async (): Promise<Partial<HardhatRuntimeEnvironmentHooks>> => ({
  created: async (context, hre) => {
    if (
      !context.globalOptions.gasStats &&
      context.globalOptions.gasStatsJson === undefined
    ) {
      return;
    }

    if (GasAnalyticsManagerImplementation === undefined) {
      ({ GasAnalyticsManagerImplementation } = await import(
        "../gas-analytics-manager.js"
      ));
    }

    const gasAnalyticsManager = new GasAnalyticsManagerImplementation(
      hre.config.paths.cache,
    );

    setGasAnalyticsManager(hre, gasAnalyticsManager);

    // NOTE: We register this hook dynamically to avoid a circular dependency
    // between gas-analytics and network-manager plugins. The network-manager
    // checks for the existence of onGasReported handlers to determine if gas
    // analytics is enabled, rather than directly checking the global option.
    hre.hooks.registerHandlers("network", {
      onGasMeasurement: (_context, gasMeasurement) => {
        gasAnalyticsManager.addGasMeasurement(gasMeasurement);
      },
    });
  },
});

