  getKeystoreFilePath,
} from "../utils/get-keystore-file-path.js";

const log = createDebug("hardhat:keystore:hook-handlers:config");

export default async (): Promise<Partial<ConfigHooks>> => {
  const handlers: Partial<ConfigHooks> = {
    resolveUserConfig: async (
      userConfig,
      resolveConfigurationVariable,
      next,
    ) => {
      const resolvedConfig = await next(
        userConfig,
        resolveConfigurationVariable,
      );

      const defaultKeystoreFilePath = await getKeystoreFilePath();
      const defaultDevKeystoreFilePath = await getDevKeystoreFilePath();
      const defaultDevKeystorePasswordFilePath =
        await getDevKeystorePasswordFilePath();

      log(`path to keystore file: ${defaultKeystoreFilePath}`);

      return {
        ...resolvedConfig,
        keystore: {
          filePath: defaultKeystoreFilePath,
          devFilePath: defaultDevKeystoreFilePath,
          devPasswordFilePath: defaultDevKeystorePasswordFilePath,
        },
      };
    },
  };

  return handlers;
};

program
	.command('init')
	.argument('[folder]', 'folder to initialize the project in')
	.option('--install', 'auto-install dependencies with pnpm')
	.description('Initialize a new hardhat-deploy project')
	.action(async (folder?: string, options?: {install?: boolean}) => {
		let targetFolder = folder;
		let autoInstall = options?.install ?? false;

		// If no folder specified, ask user
		if (!targetFolder) {
			targetFolder = await askFolder();
			// If we prompted for folder, also prompt for auto-install
			autoInstall = await askAutoInstall();
		}

		// Normalize path
		targetFolder = targetFolder.trim();

		// Check if folder is empty
		if (!isFolderEmpty(targetFolder)) {
			console.error(
				`Error: Folder "${targetFolder}" is not empty. Please specify an empty folder or a new folder path.`,
			);
			process.exit(1);
		}

		// Generate project
		generateProject(targetFolder);

		// Auto-install if requested
		if (autoInstall) {
			try {
				await runPnpmInstall(targetFolder);
			} catch (error) {
				console.error('Failed to install dependencies:', error);
				console.log('\nYou can install dependencies manually:');
				console.log(`  cd ${targetFolder === './' ? '.' : targetFolder}`);
				console.log('  pnpm install');
				process.exit(1);
			}
		}

		// Show next steps
		console.log(`\nNext steps:`);
		console.log(`  cd ${targetFolder === './' ? '.' : targetFolder}`);
		if (!autoInstall) {
			console.log(`  pnpm install`);
		}
		console.log(`  pnpm hardhat test`);
	});

import type {
  Hex,
  ReadContractReturnType,
  WriteContractReturnType,
} from "viem";

import assert from "node:assert/strict";

import { ensureError } from "@nomicfoundation/hardhat-utils/error";
import { decodeErrorResult } from "viem";

import { isKnownErrorSelector } from "./error-string.js";
import { extractRevertError } from "./extract-revert-error.js";

export async function handleRevert(
  contractFn: Promise<ReadContractReturnType | WriteContractReturnType>,
): Promise<
  | {
      args: string[];
      isPanicError: boolean;
      data: Hex;
    }
  | {
      errorWithoutReason: true;
    }
> {
  try {
    await contractFn;
  } catch (error) {
    ensureError(error);

    const rawError = extractRevertError(error);

    if (
      isKnownErrorSelector(rawError.data) === false &&
      rawError.data !== "0x"
    ) {
      assert.fail(
        `The function was expected to revert with a non custom error, but it instead reverted with a custom error. ${rawError.message}`,
      );
    }

    if (rawError.data === "0x") {
      return {
        errorWithoutReason: true,
      };
    }

    const decodedError = decodeErrorResult({ data: rawError.data });

    return {
      args: decodedError.args.map((a) => String(a)),
      isPanicError: decodedError.errorName === "Panic",
      data: rawError.data,
    };
  }

  assert.fail("The function was expected to revert, but it did not revert");
}

import type { HardhatEthers } from "@nomicfoundation/hardhat-ethers/types";
import type { Addressable } from "ethers";

import { toBigInt } from "@nomicfoundation/hardhat-utils/bigint";
import { ensureError } from "@nomicfoundation/hardhat-utils/error";
import { assert as chaiAssert } from "chai";

import { getAddressOf } from "./account.js";
import { assertCanBeConvertedToBigint } from "./asserts.js";

export interface BalanceChangeOptions {
  includeFee?: boolean;
}

export function getAddresses(
  accounts: Array<Addressable | string>,
): Promise<string[]> {
  return Promise.all(accounts.map((account) => getAddressOf(account)));
}

export async function getBalances(
  ethers: HardhatEthers,
  accounts: Array<Addressable | string>,
  blockNumber: number,
): Promise<bigint[]> {
  return await Promise.all(
    accounts.map(async (account) => {
      const address = await getAddressOf(account);

      let result;
      try {
        result = await ethers.provider.getBalance(address, blockNumber);
      } catch (cause) {
        try {
          chaiAssert.fail(
            "Failed to get the balance of the account " + address,
          );
        } catch (e) {
          ensureError(e);
          e.cause = cause;

          throw e;
        }
      }

      assertCanBeConvertedToBigint(result);

      return toBigInt(result);
    }),
  );
}

